import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { Observable } from 'rxjs';
import { AuthService } from 'src/app/service/auth.service';
@Component({
  selector: 'app-profile',
  templateUrl: './profile.component.html',
  styleUrls: ['./profile.component.css']
})
export class ProfileComponent implements OnInit {
  userForm: FormGroup;
  user$:Observable<any>
  userProfileImage:File

  constructor(private formBuilder: FormBuilder,private authService:AuthService,private router:Router) { }

  uploadProfileImage(event){
    if(event.target.files[0] != undefined){
      console.log(event.target.files[0])
      const formData = new FormData();
      formData.append('avatar',event.target.files[0])
      this.authService.updateProfileImage(formData).subscribe(
        (data)=>{
          console.log(data)
          
        }
      )
    }
  }

  updateProfile() {
    if (this.userForm.valid) {
      var body = {}
      Object.keys(this.userForm.controls).forEach(key => {
        const control = this.userForm.get(key);
        if (control.dirty) {
          body[key] = control.value;
        }
      }); 
      this.user$ = this.authService.updateUser(body)
    }
  }

  deleteMyAccount(){
    console.log('Account Deleted')
    this.authService.deleteAccount().subscribe(
      (data)=>{
        console.log("done")
        localStorage.removeItem('token')
        this.authService.authStatusValue = false
        this.router.navigate(['/auth'])
      }
    )
  }

  ngOnInit(): void {

    this.user$ = this.authService.getUser()

    this.userForm = this.formBuilder.group({
      username: ['', [Validators.required, Validators.minLength(2)]],
      name:['', [Validators.required]],
      email: ['', [Validators.required, Validators.email]],
      password:['', [Validators.minLength(6)]]
    });

    
    this.authService.getUser().subscribe(
      (data:any)=>{
        this.userForm.patchValue({username:data.user.username,name:data.user.name,email:data.user.email})
      }
    )

  }

}
