import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { AuthService } from 'src/app/service/auth.service';
import { Router } from '@angular/router';
import { HttpErrorResponse } from '@angular/common/http';


@Component({
  selector: 'app-signup-signin',
  templateUrl: './signup-signin.component.html',
  styleUrls: ['./signup-signin.component.css']
})
export class SignupSigninComponent implements OnInit {

  inSubmission:boolean = false
  errorMessage:HttpErrorResponse

  signinForm:FormGroup  
  signupForm:FormGroup
  constructor(private formBuilder:FormBuilder,public authService:AuthService,private router:Router){}

  async SignupSigninForm(){
    this.inSubmission = true
    try{
      if(this.authService.showForm()){
        console.log(this.signinForm.value)
        this.authService.signin(this.signinForm.value).subscribe(
          (userData:{user,token})=>{
            console.log(userData)
            this.inSubmission = false
            localStorage.setItem('token',`Bearer ${userData.token}`)
            this.authService.authStatusValue = true
            this.router.navigate(['/'])
          },
          (error:HttpErrorResponse)=>{
            this.inSubmission = false
            this.errorMessage = error.error
          }
        )
      }
      else{
        console.log(this.signupForm.value)
        this.authService.signup(this.signupForm.value).subscribe(
          (userData:{user,token})=>{
            console.log(userData)
            this.inSubmission = false
            localStorage.setItem('token',`Bearer ${userData.token}`)
            this.authService.authStatusValue = true
            this.router.navigate(['/'])
          },
          (error:HttpErrorResponse)=>{
            this.inSubmission = false
            this.errorMessage = error.error
          }
        )
      }
    }
    catch(e){
      console.log(e)
    }
  }

  changeForm(){
    this.authService.changeForm()
  }

  ngOnInit(): void {
    this.signinForm = this.formBuilder.group({
      email:[null,[Validators.required,Validators.email]],
      password:[null,[Validators.required,Validators.minLength(6)]]
    })
    this.signupForm = this.formBuilder.group({
      username:[null,[Validators.required]],
      name:[null,[Validators.required]],
      email:[null,[Validators.required,Validators.email]],
      password:[null,[Validators.required,Validators.minLength(6)]]      
    })

  }

}
